import{_ as t,o as r,c as a,a2 as n}from"./chunks/framework.DlS9Teyw.js";const h=JSON.parse('{"title":"Provenance and Attribute Groups","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/provenance.md","filePath":"implementation/provenance.md","lastUpdated":1780662820000}'),o={name:"implementation/provenance.md"};function i(s,e,u,c,l,p){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="provenance-and-attribute-groups" tabindex="-1">Provenance and Attribute Groups <a class="header-anchor" href="#provenance-and-attribute-groups" aria-label="Permalink to &quot;Provenance and Attribute Groups&quot;">​</a></h1><p>During processing, TORCH assigns each resource to one or more <strong>attribute groups</strong> based on the CRTDL definition and the reference resolution process.</p><p>After extraction, TORCH documents the relationship between attribute groups and the resulting resources using <strong>FHIR Provenance</strong> resources. Each attribute group produces one corresponding Provenance resource.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The Provenance resources provide <strong>traceability and interpretability</strong> of the extraction result:</p><ul><li>They document <strong>which attribute group caused which resources to be included</strong> in the output.</li><li>They allow consumers to understand the <strong>origin of extracted data</strong> within the CRTDL definition.</li><li>They support auditing and reproducibility of the extraction process.</li></ul><h2 id="structure" tabindex="-1">Structure <a class="header-anchor" href="#structure" aria-label="Permalink to &quot;Structure&quot;">​</a></h2><p>For each attribute group:</p><ul><li>A <strong>Provenance</strong> resource is created.</li><li>The <strong>targets</strong> of the Provenance resource are the extracted FHIR resources that were assigned to that attribute group.</li><li>The Provenance resource references the <strong>attribute group identifier</strong>.</li></ul><p>This establishes a many-to-many relationship:</p><ul><li>A resource can be linked to multiple attribute groups.</li><li>An attribute group can reference multiple resources.</li></ul><h2 id="semantics" tabindex="-1">Semantics <a class="header-anchor" href="#semantics" aria-label="Permalink to &quot;Semantics&quot;">​</a></h2><ul><li>Provenance reflects the <strong>assignment after extraction</strong>.</li><li>It captures <strong>why a resource is present in the output</strong>, i.e. which attribute group selected it.</li></ul><h2 id="limitations-and-considerations" tabindex="-1">Limitations and Considerations <a class="header-anchor" href="#limitations-and-considerations" aria-label="Permalink to &quot;Limitations and Considerations&quot;">​</a></h2><ul><li><p><strong>Resource-level granularity</strong><br> Provenance is recorded at the resource level and does not indicate which specific elements within a resource were selected.</p></li><li><p><strong>Shared resources across groups</strong><br> If a resource is relevant to multiple attribute groups, it will appear in multiple Provenance resources.</p></li></ul>',15)])])}const g=t(o,[["render",i]]);export{h as __pageData,g as default};
